import { Box, Pagination, Skeleton } from "@mui/material";
import React, { useCallback, useEffect, useRef, useState } from "react";
import "./Main.scss";
import { Product } from "../../types/products";
import { ProductCard } from "../ProductCard/ProductCard";
import { Search } from "../Search/Search";
import { getProductsFromAPI } from "../../api/getProductsFromAPI";
import { PromiseProducts } from "../../react-app-env";
import { useDispatch, useSelector } from "react-redux";
import { setProducts } from "../../redux/slices/productsSlice";
import { RootState } from "../../redux/store/store";
import { ItemsPerPageSelector } from "../ItemsPerPageSelector/ItemsPerPageSelector";
import { SortBy } from "../SortBy/SortBy";
import { sorting } from "../../utils/sorting";
import { useLocation } from "react-router-dom";
import { setPage } from "../../redux/slices/pageSlice";

const ProductSkeleton: React.FC = () => (
  <Box className="product-card" data-testid="product-skeleton">
    <Box className="product-card__inner" sx={{ padding: '16px' }}>
      <Skeleton variant="rectangular" height={260} sx={{ borderRadius: '8px', marginBottom: '16px' }} />
      <Skeleton variant="text" width="40%" height={20} sx={{ marginBottom: '4px' }} />
      <Skeleton variant="text" width="80%" height={24} sx={{ marginBottom: '8px' }} />
      <Skeleton variant="text" width="30%" height={24} sx={{ marginBottom: '8px' }} />
      <Skeleton variant="text" width="100%" height={16} />
      <Skeleton variant="text" width="90%" height={16} sx={{ marginBottom: '16px' }} />
      <Skeleton variant="rectangular" height={36} sx={{ borderRadius: '6px' }} />
    </Box>
  </Box>
);

export const Main: React.FC = () => {
  const productsFromRedux = useSelector(
    (state: RootState) => state.products.products
  );
  const [itemsPerPage, setItemsPerPage] = useState(12);
  const [productsToRender, setProductsToRender] = useState([]);
  const [pages, setPages] = useState(1);
  const { page } = useSelector((state: RootState) => state.page);
  const [sortBy, setSortBy] = useState("");
  const [query, setQuery] = useState("");
  const [activeSearch, setActiveSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const dispatch = useDispatch();
  const location = useLocation();
  const prevPathnameRef = useRef(location.pathname);

  const liftingQuery = (arg: string) => {
    setQuery(arg);
  };

  const liftingSortBy = (arg: string) => {
    setSortBy(arg);
  };

  const liftingItemsPerPage = (arg: number) => {
    setItemsPerPage(arg);
  };

  const getProducts = useCallback(async (arg: string) => {
    let queryLocation = "";
    let search = "";

    setActiveSearch(arg);
    setLoading(true);

    if (location.pathname !== "/") {
      queryLocation = "/category" + location.pathname;
    }

    try {
      let res: PromiseProducts;

      if (arg !== "") {
        search = "/search?q=" + encodeURIComponent(arg);
        res = await getProductsFromAPI(
          `${search}&limit=${itemsPerPage}&skip=${(page - 1) * itemsPerPage}`
        );
      } else {
        res = await getProductsFromAPI(
          `${queryLocation}?limit=${itemsPerPage}&skip=${
            (page - 1) * itemsPerPage
          }`
        );
      }

      setPages(Math.ceil(res.total / itemsPerPage));
      dispatch(setProducts(res.products));
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error("Failed to load products:", error);
    } finally {
      setLoading(false);
    }
  }, [itemsPerPage, page, location.pathname, dispatch]);

  useEffect(() => {
    const pathnameChanged = prevPathnameRef.current !== location.pathname;
    prevPathnameRef.current = location.pathname;

    if (pathnameChanged) {
      setActiveSearch("");
      setQuery("");
      getProducts("");
    } else {
      getProducts(activeSearch);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [getProducts]);

  useEffect(() => {
    sorting(productsFromRedux, sortBy, setProductsToRender);
  }, [sortBy, itemsPerPage, page, productsFromRedux]);

  return (
    <main
      className="main"
      style={{
        paddingBottom: "20px",
      }}
    >
      <div
        className="container"
        style={{
          margin: "20px auto",
        }}
      >
        <Box className="toolbar">
          <Search
            query={query}
            liftingQuery={liftingQuery}
            getProducts={getProducts}
          />

          <Box className="toolbar__controls">
            <SortBy sortBy={sortBy} liftingSortBy={liftingSortBy} />
            <ItemsPerPageSelector
              itemsPerPage={itemsPerPage}
              liftingItemsPerPage={liftingItemsPerPage}
            />
          </Box>
        </Box>

        <Box
          sx={{
            display: "flex",
            justifyContent: "center",
            margin: "16px 0",
          }}
        >
          <Pagination
            count={pages}
            page={page}
            onChange={(_, num) => {
              dispatch(setPage(num));
            }}
            sx={{
              '& .MuiPaginationItem-root': {
                color: 'var(--color-text-secondary)',
                fontSize: '0.85rem',
                '&.Mui-selected': {
                  backgroundColor: 'var(--color-btn-primary)',
                  color: 'var(--color-btn-primary-text)',
                  '&:hover': {
                    backgroundColor: 'var(--color-btn-primary-hover)',
                  },
                },
                '&:hover': {
                  backgroundColor: 'var(--color-bg-secondary)',
                },
              },
            }}
          />
        </Box>

        <Box
          className="product-list"
          sx={{
            margin: "10px -5px",
            display: "flex",
            flexWrap: "wrap",
            rowGap: "25px",
            justifyContent: "start",
          }}
        >
          {loading ? (
            Array.from({ length: itemsPerPage }, (_, i) => (
              <ProductSkeleton key={i} />
            ))
          ) : (
            productsToRender.map((product: Product) => (
              <ProductCard key={product.id} product={product} />
            ))
          )}
        </Box>
      </div>
    </main>
  );
};
